questions.question_ja:
以下のコードの出力は何ですか？

```javascript
function createFunctions() {
  let result = [];
  for (let i = 0; i < 3; i++) {
    result.push(function() {
      let j = i;
      return function() {
        return j++;
      };
    });
  }
  return result;
}

const fns = createFunctions();
const a = fns[0]();
const b = fns[0]();
console.log(a()); // ?
console.log(a()); // ?
console.log(b()); // ?
```

